/**
 * Agent 類型
 */
export type AgentType = 'codex' | 'claude' | 'gemini' | 'cursor' | 'agy';

/**
 * CLI 選項
 */
export interface CliOptions {
  agentType: AgentType;
  raw: boolean;
  project?: string;
  follow: boolean;
  verbose: boolean;
  /** Suppress non-error output messages */
  quiet: boolean;
  /** File polling interval in milliseconds (default: 500) */
  sleepInterval: number;
  /** Number of initial lines to show per file (default: all) */
  lines?: number;
  /** Claude/Codex: tail subagent log (true = latest, string = specific ID) */
  subagent?: string | true;
  /** Claude/Codex: interactive mode for switching between main session and subagents (Codex: Phase 3) */
  interactive: boolean;
  /** Claude/Codex: include subagent content in output (non-interactive mode) */
  withSubagents: boolean;
  /** Auto-switch to latest main session in project */
  autoSwitch: boolean;
  /** Claude/Codex: auto-open tmux pane for each new subagent (Codex: Phase 2) */
  pane: boolean;
  /** List recent sessions instead of tailing */
  list: boolean;
  /** Show session summary (first N + last M lines) */
  summary: boolean;
  /** Optional session ID to load (partial match supported) */
  sessionId?: string;
}

/**
 * Parser 設定選項
 */
export interface ParserOptions {
  verbose: boolean;
}

/**
 * Session 檔案資訊
 */
export interface SessionFile {
  path: string;
  mtime: Date;
  agentType: AgentType;
  /** Claude Code custom session title (from /rename command) */
  customTitle?: string;
}

/**
 * 專案資訊（用於 auto-switch）
 */
export interface ProjectInfo {
  /** 專案目錄路徑（用於 session 搜尋範圍） */
  projectDir: string;
  /** 顯示名稱（用於日誌輸出） */
  displayName?: string;
}

/**
 * Claude Session 查找結果（支援 subagent 關聯）
 * 當指定 subagent ID 時，會同時返回主 session 和 subagent
 */
export interface ClaudeSessionResult {
  main: SessionFile;
  subagent?: SessionFile;
}

/**
 * Session 列表項目（用於 --list 輸出）
 */
export interface SessionListItem extends SessionFile {
  /** 顯示用短識別碼 */
  shortId: string;
  /** 專案識別（decoded path, cwd, slug, dir name） */
  project?: string;
  /** 最後活動時間（從 session 內容讀取，比 file mtime 更準確） */
  lastActivityTime?: Date;
}

/**
 * JSONL 解析結果
 */
export interface ParsedLine {
  type: string;
  timestamp: string;
  raw: unknown;
  formatted: string;
  /** Tool 名稱（僅 function_call 類型使用，用於顏色判斷） */
  toolName?: string;
  /** 來源標籤（多檔案監控時用於區分來源，如 "[MAIN]" 或 "[a0627b6]"） */
  sourceLabel?: string;
  /** 是否為 Task (or Agent) tool_use（用於早期 Subagent 偵測） */
  isTaskToolUse?: boolean;
  /** Task (or Agent) tool_use 的 description 欄位（用於 pane 命名） */
  taskDescription?: string;
  /** Whether this is a custom-title event (Claude only) */
  isCustomTitle?: boolean;
  /** The custom title value from the event */
  customTitleValue?: string;
}

import type {
  AgentType,
  ClaudeSessionResult,
  ParsedLine,
  ProjectInfo,
  SessionFile,
  SessionListItem,
} from '../core/types.ts';

/**
 * Session 檔案發現器介面
 */
export interface SessionFinder {
  /**
   * 取得基礎目錄
   */
  getBaseDir(): string;

  /**
   * 找到最新的 session 檔案
   */
  findLatest(options: { project?: string }): Promise<SessionFile | null>;

  /**
   * 找到 subagent 檔案（可選實作，目前只有 Claude 支援）
   * @param options.subagentId - 指定的 subagent ID，不提供則找最新的
   */
  findSubagent?(options: {
    project?: string;
    subagentId?: string;
  }): Promise<SessionFile | null>;

  /**
   * 依 session ID 查找 session 檔案（可選實作）
   * 支援 partial match：精確 > 前綴 > 包含
   * 多重匹配時選擇 mtime 最新的
   * @param sessionId - 使用者提供的 session ID（可為簡化格式或部分 ID）
   * @param options.project - 專案過濾
   * @returns SessionFile（一般情況）或 ClaudeSessionResult（Claude subagent 情況）
   */
  findBySessionId?(
    sessionId: string,
    options: { project?: string }
  ): Promise<SessionFile | ClaudeSessionResult | null>;

  /**
   * 從 session 檔案取得專案資訊（用於 auto-switch）
   * @param sessionPath - session 檔案路徑
   * @returns 專案資訊，若無法識別則回傳 null
   */
  getProjectInfo?(sessionPath: string): Promise<ProjectInfo | null>;

  /**
   * 在指定專案範圍內找最新的 session（用於 auto-switch）
   * @param projectDir - 專案目錄識別
   */
  findLatestInProject?(projectDir: string): Promise<SessionFile | null>;

  /**
   * 列出所有 session（按 mtime 降序）
   * @param options.project - 專案過濾
   * @param options.limit - 最大回傳數量（預設 20）
   */
  listSessions?(options: {
    project?: string;
    limit?: number;
  }): Promise<SessionListItem[]>;
}

/**
 * JSONL 行解析器介面
 */
export interface LineParser {
  /**
   * 解析單行 JSONL
   */
  parse(line: string): ParsedLine | null;

  /**
   * 設定會話 ID（可選，如 AgyAgent 需要它來識別解析對象）
   */
  setConversationId?(id: string): void;
}

/**
 * Agent 介面
 */
export interface Agent {
  readonly type: AgentType;
  readonly finder: SessionFinder;
  readonly parser: LineParser;
}

