1	import { watch, type FSWatcher } from 'node:fs';
2	import { stat } from 'node:fs/promises';
3	
4	export interface WatchOptions {
5	  follow: boolean;
6	  onLine: (line: string) => void;
7	  onError?: (error: Error) => void;
8	  /** JSON 模式：不分割行，把整個檔案當作一個整體傳給 onLine */
9	  jsonMode?: boolean;
10	  /** Polling interval in milliseconds (default: 500) */
11	  pollInterval?: number;
12	  /** Number of initial lines to show (default: all) */
13	  initialLines?: number;
14	}
15	
16	/**
17	 * 檔案監控器 - 實作 tail -f 效果
18	 */
19	export class FileWatcher {
20	  private watcher: FSWatcher | null = null;
21	  private processedLines = 0;
22	  private isWatching = false;
23	  private jsonMode = false;
24	  private lastContentHash = '';
25	  private lastMtimeMs = 0;
26	  private lastSize = 0;
27	  private filePath: string | null = null;
28	  private options: WatchOptions | null = null;
29	  private isRestarting = false;
30	  private pollTimer: ReturnType<typeof setInterval> | null = null;
31	  private isPolling = false;
32	  private pollInterval = 500;
33	  private isFirstRead = true;
34	  // 競態條件防護：isProcessing 和 pending 標誌
35	  private isProcessing = false;
36	  private pendingRead = false;
37	
38	  /**
39	   * 開始監控檔案
40	   */
41	  async start(filePath: string, options: WatchOptions): Promise<void> {
42	    this.jsonMode = options.jsonMode || false;
43	    this.filePath = filePath;
44	    this.options = options;
45	    this.pollInterval = options.pollInterval || 500;
46	    this.isFirstRead = true;
47	
48	    // 初始讀取現有內容（直接呼叫，不需排程）
49	    await this.readAndProcess(filePath, options.onLine);
50	    await this.updateMtime(filePath);
51	
52	    // 如果需要持續監控
53	    if (options.follow) {
54	      this.isWatching = true;
55	      this.startWatcher();
56	      this.startPolling();
57	    }
58	  }
59	
60	  /**
61	   * 排程讀取操作（防止競態條件）
62	   * 如果正在處理，設為 pending 並返回
63	   * 處理完成後如果 pending 為 true，再執行一次
64	   */
65	  private async scheduleRead(): Promise<void> {
66	    if (!this.filePath || !this.options) return;
67	
68	    if (this.isProcessing) {
69	      this.pendingRead = true;
70	      return;
71	    }
72	
73	    this.isProcessing = true;
74	    this.pendingRead = false;
75	
76	    try {
77	      await this.readAndProcess(this.filePath, this.options.onLine);
78	      await this.updateMtime(this.filePath);
79	
80	      // 處理完成後，如果有 pending 請求，再執行一次
81	      if (this.pendingRead) {
82	        this.pendingRead = false;
83	        await this.scheduleRead();
84	      }
85	    } catch (error) {
86	      this.options.onError?.(error as Error);
87	    } finally {
88	      this.isProcessing = false;
89	    }
90	  }
91	
92	  /**
93	   * 讀取並處理檔案內容
94	   */
95	  private async readAndProcess(
96	    filePath: string,
97	    onLine: (line: string) => void
98	  ): Promise<void> {
99	    const file = Bun.file(filePath);
100	    const content = await file.text();
101	
102	    if (this.jsonMode) {
103	      // JSON 模式：把整個檔案當作一個整體
104	      // 使用簡單的 hash 來檢測內容是否有變化
105	      const contentHash = Bun.hash(content).toString();
106	      if (contentHash !== this.lastContentHash) {
107	        this.lastContentHash = contentHash;
108	        onLine(content);
109	      }
110	    } else {
111	      // JSONL 模式：按行分割
112	      const lines = content.split('\n').filter(Boolean);
113	
114	      // 檔案被截斷或重寫時，重置已處理行數
115	      if (lines.length < this.processedLines) {
116	        this.processedLines = 0;
117	      } else if (lines.length <= this.processedLines) {
118	        const contentHash = Bun.hash(content).toString();
119	        if (this.lastContentHash && this.lastContentHash !== contentHash) {
120	          this.processedLines = 0;
121	        }
122	        this.lastContentHash = contentHash;
123	      }
124	
125	      // 處理 initialLines 選項
126	      let linesToProcess: string[];
127	      if (this.isFirstRead && this.options?.initialLines !== undefined) {
128	        const n = this.options.initialLines;
129	
130	        if (n < 0) {
131	          linesToProcess = lines; // 負數：全部
