import chalk from 'chalk';
import type { LineParser } from '../agents/agent.interface.ts';
import type { ParsedLine } from '../core/types.ts';
import type { JournalEvent } from './types.ts';
```

Module-local helpers (do NOT reuse `src/utils/text.ts:truncate` — its head+tail-with-omitted-msg semantics don't apply here):

```typescript
function truncateLine(str: string, max: number): string {
  return str.length <= max ? str : str.slice(0, max) + '…';
}

function safeStringify(value: unknown): string {
  if (typeof value === 'string') return value;
  if (value === null || value === undefined) return String(value);
  try {
    return JSON.stringify(value);
  } catch {
    // Cyclic references or other JSON.stringify failures
    return '[object]';
  }
}
