import { WorkflowSessionFinder } from './workflow-agent.ts';

export class ClaudeSessionFinder implements SessionFinder {
  private baseDir: string;
  private _wf: WorkflowSessionFinder | null = null;

  constructor() {
    this.baseDir = join(homedir(), '.claude', 'projects');
  }

  /** Lazy workflow finder bound to current baseDir — re-created when test
   *  injection changes baseDir after construction. WorkflowSessionFinder
   *  constructor accepts an optional baseDir override. */
  private get workflowFinder(): WorkflowSessionFinder {
    if (!this._wf || this._wf.getBaseDir() !== this.baseDir) {
      this._wf = new WorkflowSessionFinder(this.baseDir);
    }
    return this._wf;
  }

  // ...

  /** Extracted helper — current listSessions body (collect + slice + enrich
   *  + re-sort), preserved verbatim. */
  private async _collectAndEnrichMainSessions(options: {
    project?: string;
    limit: number;
  }): Promise<SessionListItem[]> {
    const files = await this._collectMainSessions({ project: options.project });
    const sliced = files.slice(0, options.limit);

    await Promise.all(
      sliced.map(async (item) => {
        const [lastTs, title, cwd] = await Promise.all([
          readLastTimestampFromJSONL(item.path),
          readCustomTitleFromTail(item.path),
          readCwdFromHead(item.path),
        ]);
        item.lastActivityTime = lastTs ?? undefined;
        if (title) item.customTitle = title;
        if (cwd) item.project = cwd;
      })
    );

    sliced.sort((a, b) => {
      const ta = (a.lastActivityTime ?? a.mtime).getTime();
      const tb = (b.lastActivityTime ?? b.mtime).getTime();
      return tb - ta;
    });

    return sliced;
  }

  async listSessions(options: {
    project?: string;
    limit?: number;
  }): Promise<SessionListItem[]> {
    const limit = options.limit ?? 20;

    // 1. Enrich main sessions first (preserves existing slice→enrich→re-sort
    //    behavior — sessions whose mtime is older than `limit` cutoff but
    //    whose lastActivityTime is newer still bubble up).
    const mainItems = await this._collectAndEnrichMainSessions({
      project: options.project,
      limit,
    });

    // 2. Workflow items already carry snapshot metadata — no enrich needed.
    //    Pass limit too so workflow side caps its own collection.
    const wfItems = await this.workflowFinder.listSessions({
      project: options.project,
      limit,
    });

    // 3. Merge by activity time and slice to final limit.
    const merged: SessionListItem[] = [...mainItems, ...wfItems].sort((a, b) => {
      const ta = (a.lastActivityTime ?? a.mtime).getTime();
      const tb = (b.lastActivityTime ?? b.mtime).getTime();
      return tb - ta;
    });

    return merged.slice(0, limit);
  }
}
```

> **Trade-off (corrected)**: SPEC §7.4 sample enriches main first, then merges. The original plan reversed this to "merge → slice → enrich" — wrong because it drops items that would bubble up via `lastActivityTime`. Reverting to SPEC §7.4 order preserves existing `tests/agents/claude-list-sessions.test.ts` behavior verbatim and matches the SPEC.

