# P3: WorkflowDetector path B + WorkflowAttachment + `--workflow` CLI + dispatcher

> SPEC sections: §9.1 path B, §9.3, §10.2, §10.4, §11.1
> Acceptance targets: T4, T5, T6, T7

## Overview

P3 turns the foundations from P1/P2 into actual tail behavior. After this phase, `agent-tail claude --workflow <runId>` shows journal + workflow agent transcripts in real time. `--no-workflow-agents` opts out of agent tailing. Snapshot integration is P4; main-session early detection (path A) is P5; interactive mode is P6; tmux pane is P7.

What lands:

1. `WorkflowDetector` — directory-watch on `{session}/workflows/` (path B), emits new wf runId discoveries via `onNewWorkflow`. Path A (main JSONL Workflow tool_use) is P5.
2. `WorkflowAttachment` — per-workflow lifecycle: journal FileWatcher + initial agent scan + new-agent directory watcher + sequential ordered start. **No** snapshot watcher yet (P4).
3. CLI flags in `src/cli/parser.ts`: `--workflow [runId]`, `--no-workflow-agents`, `--no-workflow-attach`, `--workflow-pane` (defined; pane impl P7).
4. Dispatcher in `src/index.ts`: when `options.workflow !== undefined`, route Claude to `startClaudeWorkflowMultiWatch`.
5. CLI mutual-exclusion rules per SPEC §11.2 enforced in `parser.ts`.

## Implementation Steps

### Step 1 — `src/claude-workflow/workflow-detector.ts`

```typescript
import { watch, type FSWatcher } from 'node:fs';
import type { OutputHandler } from '../core/detector-interfaces.ts';
import {
  getWorkflowsDir,
  getWorkflowSubagentsDir,
  getWorkflowSnapshotPath,
  parseWorkflowSnapshotFilename,
} from './paths.ts';
import type { DetectedWorkflow } from './types.ts';

export interface WorkflowDetectorConfig {
  /** Per SPEC §6.2 — session-specific paths */
  sessionUuid: string;
  /** Absolute path to {sessionDir} = ~/.claude/projects/{enc-cwd}/{UUID} */
  sessionDir: string;
  onNewWorkflow: (workflow: DetectedWorkflow) => Promise<void> | void;
  outputHandler: OutputHandler;
}

export class WorkflowDetector {
  private dirWatcher: FSWatcher | null = null;
  private knownRunIds = new Set<string>();
  private stopped = false;

  constructor(private readonly config: WorkflowDetectorConfig) {}

  /** Start path B (directory watch on {session}/workflows/). */
  async start(): Promise<void> {
    const workflowsDir = getWorkflowsDir(this.config.sessionDir);
    try {
      this.dirWatcher = watch(workflowsDir, (eventType, filename) => {
        if (this.stopped || !filename) return;
        const runId = parseWorkflowSnapshotFilename(filename);
        if (!runId) return;
        if (!this.markRunIdKnown(runId)) return;
        void this._handleNewRunId(runId, /* retries */ 10);
      });
      this.dirWatcher.on('error', (err) =>
        this.config.outputHandler.debug(
          `[workflow-detector] dir watch error: ${err}`
        )
      );
    } catch (err) {
      // Dir doesn't exist yet — workflow path B is best-effort.
      this.config.outputHandler.debug(
        `[workflow-detector] watch ${workflowsDir} failed: ${err}`
      );
    }
  }

  /** SPEC §9.1.1 — synchronous mark + insert (race-safe). */
  markRunIdKnown(runId: string): boolean {
    if (this.knownRunIds.has(runId)) return false;
    this.knownRunIds.add(runId);
    return true;
  }

  /**
   * Pre-register a runId as known. Used by dispatchers that already know
   * the target runId (e.g. `--workflow <runId>` direct attach) so path B
   * doesn't emit a duplicate onNewWorkflow.
   */
  prefillKnown(runId: string): void {
    this.knownRunIds.add(runId);
  }

  stop(): void {
    if (this.stopped) return;
    this.stopped = true;
    this.dirWatcher?.close();
    this.dirWatcher = null;
  }

  private async _handleNewRunId(runId: string, retries: number): Promise<void> {
    const snapshotPath = getWorkflowSnapshotPath(
      this.config.sessionDir,
      runId
    );
    const transcriptDir = `${getWorkflowSubagentsDir(this.config.sessionDir)}/${runId}`;
    let succeeded = false;
    try {
      await this.config.onNewWorkflow({
        runId,
        transcriptDir,
        snapshotPath,
      });
      succeeded = true;
    } catch (err) {
      this.config.outputHandler.debug(
        `[workflow-detector] onNewWorkflow ${runId} failed: ${err}`
      );
    } finally {
      if (!succeeded) {
        // Rollback for retry (path A may also pick it up later).
        this.knownRunIds.delete(runId);
        if (retries > 0) {
          await new Promise((r) => setTimeout(r, 100));
          if (!this.stopped && this.markRunIdKnown(runId)) {
            void this._handleNewRunId(runId, retries - 1);
          }
        }
      }
    }
  }
}
```

### Step 2 — `src/claude-workflow/watch-builder.ts`

#### `WorkflowAttachment` — per-workflow lifecycle

```typescript
import { watch, type FSWatcher } from 'node:fs';
import { join } from 'node:path';
import { Glob } from 'bun';
import { FileWatcher } from '../core/file-watcher.ts';
import type {
  OutputHandler,
  SessionHandler,
} from '../core/detector-interfaces.ts';
import type { Formatter } from '../formatters/formatter.interface.ts';
import { ClaudeAgent } from '../agents/claude/claude-agent.ts';
import type { LineParser } from '../agents/agent.interface.ts';
import { JournalLineParser } from './journal-parser.ts';
import {
  parseWorkflowAgentFilename,
  isValidWorkflowAgentId,
} from './paths.ts';
import type { DetectedWorkflow } from './types.ts';

export interface WorkflowAttachmentConfig {
  workflow: DetectedWorkflow;
  withAgents: boolean;
  verbose: boolean;
  follow: boolean;
  pollInterval?: number;
  initialLines?: number;
  formatter: Formatter;
  /** Per-line output. label is `[wf:{runId}:journal]` or `[wf:{shortAgentId}]`. */
  onOutput: (formatted: string, label: string) => void;
  outputHandler: OutputHandler;
  sessionHandler?: SessionHandler;
}

export function makeWorkflowJournalLabel(runId: string): string {
  return `[wf:${runId}:journal]`;
}

export function makeWorkflowAgentLabel(agentId: string): string {
  return `[wf:${agentId.slice(0, 7)}]`;
}

export class WorkflowAttachment {
  private journalWatcher: FileWatcher | null = null;
  private journalParser: JournalLineParser | null = null;
  private readonly agentWatchers = new Map<string, FileWatcher>();
  private readonly agentParsers = new Map<string, LineParser>();
  private subagentDirWatcher: FSWatcher | null = null;
  private readonly knownAgentIds = new Set<string>();
  private stopped = false;

  constructor(private readonly config: WorkflowAttachmentConfig) {}

  async start(): Promise<void> {
    await this._waitForTranscriptDir(/* retries */ 10, /* intervalMs */ 100);

    // Step 1 — journal
    await this._startJournalAndFlushHistory();

    // Step 2/3 — workflow agents (initial + directory watch)
    if (this.config.withAgents) {
      await this._scanAndAttachInitialAgents();
      this._startSubagentDirWatch();
    }

    // Step 4 — snapshot watcher: P4 scope (not wired here)
  }

  /** P3 attaches via initial scan or directory watch. */
  async attachAgent(agentId: string, transcriptPath: string): Promise<void> {
    if (this.knownAgentIds.has(agentId)) return;
    this.knownAgentIds.add(agentId);

    let succeeded = false;
    try {
      const parser = new ClaudeAgent({ verbose: this.config.verbose }).parser;
      this.agentParsers.set(agentId, parser);

      const watcher = new FileWatcher();
      const label = makeWorkflowAgentLabel(agentId);
      await watcher.start(transcriptPath, {
        follow: this.config.follow,
        pollInterval: this.config.pollInterval,
        initialLines: this.config.initialLines,
        onLine: (line) => this._handleAgentLine(agentId, line, label),
        onError: (err) =>
          this.config.outputHandler.debug(
            `[wf:${this.config.workflow.runId}] agent ${agentId.slice(0, 7)} read error: ${err}`
          ),
      });
      this.agentWatchers.set(agentId, watcher);

      this.config.sessionHandler?.addSession?.(
        agentId,
        label,
        transcriptPath
      );
      this.config.sessionHandler?.updateUI?.();
      succeeded = true;
    } finally {
      if (!succeeded) {
        this.knownAgentIds.delete(agentId);
        this.agentParsers.delete(agentId);
        this.config.outputHandler.debug(
          `[wf:${this.config.workflow.runId}] attachAgent ${agentId.slice(0, 7)} failed; rolled back`
        );
      }
    }
  }

  async stop(reason: 'completed' | 'directory-removed' | 'user'): Promise<void> {
    if (this.stopped) return;
    this.stopped = true;

    this.subagentDirWatcher?.close();
    this.subagentDirWatcher = null;

    await this.journalWatcher?.stop();
    this.journalWatcher = null;

    await Promise.all(
      [...this.agentWatchers.values()].map((w) => w.stop())
    );
    this.agentWatchers.clear();

    // Notify sessionHandler
    for (const agentId of this.knownAgentIds) {
      this.config.sessionHandler?.markSessionDone?.(agentId);
    }
    this.config.sessionHandler?.markSessionDone?.(
      `wf:${this.config.workflow.runId}`
    );

    this.config.outputHandler.info(
      `[wf:${this.config.workflow.runId}] stopped (${reason})`
    );
  }

  // --- internals (omitted; see below) ---
}
```

##### Internal helpers (in same file)

```typescript
// Wait for transcriptDir to exist with retries — early-detection case.
private async _waitForTranscriptDir(
  retries: number,
  intervalMs: number
): Promise<void> {
  for (let i = 0; i < retries; i++) {
    if (this.stopped) return;
    try {
      const dir = Bun.file(this.config.workflow.transcriptDir);
      // Bun.file().exists() returns false for dirs; use stat instead.
      const { stat } = await import('node:fs/promises');
      await stat(this.config.workflow.transcriptDir);
      return; // exists
    } catch {
      await new Promise((r) => setTimeout(r, intervalMs));
    }
  }
  // Last try without throw — Step 1 journal start will simply error if
  // still missing and outputHandler.debug logs the failure.
}

private async _startJournalAndFlushHistory(): Promise<void> {
  const journalPath = join(
    this.config.workflow.transcriptDir,
    'journal.jsonl'
  );

  // Read mtime to seed parser's history timestamp
  const { stat } = await import('node:fs/promises');
  let fileMtime: Date | undefined;
  try {
    fileMtime = (await stat(journalPath)).mtime;
  } catch {
    /* journal may not exist yet — proceed */
  }

  this.journalParser = new JournalLineParser({ fileMtime });
  const label = makeWorkflowJournalLabel(this.config.workflow.runId);

  const watcher = new FileWatcher();
  this.journalWatcher = watcher;
  await watcher.start(journalPath, {
    follow: this.config.follow,
    pollInterval: this.config.pollInterval,
    initialLines: this.config.initialLines,
    onLine: (line) => this._handleJournalLine(line, label),
    onError: (err) =>
      this.config.outputHandler.debug(
        `[wf:${this.config.workflow.runId}] journal read error: ${err}`
      ),
  });

  // After initial flush, switch parser to live mode.
  this.journalParser.markLiveMode();
}

private _handleJournalLine(line: string, label: string): void {
  if (!this.journalParser) return;
  const parsed = this.journalParser.parse(line);
  if (!parsed) return;
  parsed.sourceLabel = label;
  const formatted = this.config.formatter.format(parsed);
  if (formatted) this.config.onOutput(formatted, label);
}

private _handleAgentLine(agentId: string, line: string, label: string): void {
  const parser = this.agentParsers.get(agentId);
  if (!parser) return;
  // ClaudeLineParser is stateful multi-emit; drain.
  let parsed = parser.parse(line);
  let guard = 0;
  while (parsed && guard < 100) {
    parsed.sourceLabel = label;
    const formatted = this.config.formatter.format(parsed);
    if (formatted) this.config.onOutput(formatted, label);
    parsed = parser.parse(line);
    guard++;
  }
}

private async _scanAndAttachInitialAgents(): Promise<void> {
  const glob = new Glob('agent-*.jsonl');
  const found: { agentId: string; path: string; birthtime: Date }[] = [];
  for await (const file of glob.scan({
    cwd: this.config.workflow.transcriptDir,
  })) {
    const agentId = parseWorkflowAgentFilename(file);
    if (!agentId) continue;
    const path = join(this.config.workflow.transcriptDir, file);
    try {
      const { stat } = await import('node:fs/promises');
      const stats = await stat(path);
      found.push({ agentId, path, birthtime: stats.birthtime });
    } catch {
      /* skip */
    }
  }
  found.sort((a, b) => a.birthtime.getTime() - b.birthtime.getTime());
  for (const { agentId, path } of found) {
    await this.attachAgent(agentId, path);
  }
}

private _startSubagentDirWatch(): void {
  try {
    this.subagentDirWatcher = watch(
      this.config.workflow.transcriptDir,
      (eventType, filename) => {
        if (this.stopped || !filename) return;
        const agentId = parseWorkflowAgentFilename(filename);
        if (!agentId || !isValidWorkflowAgentId(agentId)) return;
        const transcriptPath = join(
          this.config.workflow.transcriptDir,
          filename
        );
        void this.attachAgent(agentId, transcriptPath);
      }
    );
    this.subagentDirWatcher.on('error', (err) =>
      this.config.outputHandler.debug(
        `[wf:${this.config.workflow.runId}] subagent dir watch error: ${err}`
      )
    );
  } catch (err) {
    this.config.outputHandler.debug(
      `[wf:${this.config.workflow.runId}] subagent dir watch failed: ${err}`
    );
  }
}
```

