if (options.agentType === 'claude' && options.workflow !== undefined) {
  // Workflow mode dispatch.
  const wfFinder = new WorkflowSessionFinder();
  let snapshotPath: string | null = null;
  let runId: string | null = null;

  if (typeof options.workflow === 'string') {
    // --workflow <runId>
    const result = await wfFinder.findBySessionId(options.workflow, {
      project: options.project,
    });
    if (!result) {
      console.error(`Error: workflow run not found: ${options.workflow}`);
      process.exit(1);
    }
    snapshotPath = result.path;
  } else {
    // --workflow (no runId) — scope to current cwd
    const filter = cwdToClaudeProjectFilter(process.cwd());
    const result = await wfFinder.findLatest({ project: filter });
    if (!result) {
      console.error(
        'Error: no workflow runs found in current cwd. Use --list or --workflow <runId>.'
      );
      process.exit(1);
    }
    snapshotPath = result.path;
  }

  // Derive runId from snapshotPath
  const m = snapshotPath.match(/(wf_[0-9a-f]{8}-[0-9a-f]{3})\.json$/);
  if (!m) {
    console.error(`Error: failed to derive runId from ${snapshotPath}`);
    process.exit(1);
  }
  runId = m[1]!;

  await startClaudeWorkflowMultiWatch(snapshotPath, runId, formatter, options);
  return;
}
```

#### 4.2 `startClaudeWorkflowMultiWatch`

```typescript
async function startClaudeWorkflowMultiWatch(
  snapshotPath: string,
  runId: string,
  formatter: Formatter,
  options: CliOptions
): Promise<void> {
  // Derive transcriptDir from snapshotPath:
  //   .../{enc}/{UUID}/workflows/wf_*.json
  //   .../{enc}/{UUID}/subagents/workflows/wf_*/
  const parts = snapshotPath.split('/');
  const wfIdx = parts.indexOf('workflows');
  const sessionDir = parts.slice(0, wfIdx).join('/');
  const transcriptDir = join(
    sessionDir,
    'subagents',
    'workflows',
    runId
  );

  const outputHandler: OutputHandler = createConsoleOutputHandler(options);

  const attachment = new WorkflowAttachment({
    workflow: { runId, transcriptDir, snapshotPath },
    withAgents: options.withWorkflowAgents !== false,
    verbose: options.verbose,
    follow: options.follow,
    pollInterval: options.sleepInterval,
    initialLines: options.lines,
    formatter,
    onOutput: (formatted) => process.stdout.write(`${formatted}\n`),
    outputHandler,
  });

  await attachment.start();

  // Graceful shutdown
  process.once('SIGINT', () => void attachment.stop('user').then(() => process.exit(0)));
}
```

(`createConsoleOutputHandler` is the existing helper used by `startClaudeMultiWatch` — reuse it.)

### Step 5 — paths.ts already has helpers; no changes needed

P1 already shipped `getWorkflowsDir`, `getWorkflowSubagentsDir`, `parseWorkflowSnapshotFilename`, `parseWorkflowAgentFilename`. P3 just imports them.

## Trade-offs & Decisions

| # | Decision | Rationale |
|---|----------|-----------|
| D1 | `WorkflowDetector` does NOT immediately scan `workflows/` on start — only watches | Path A (main JSONL tool_result, P5) handles current-session workflows. Path B is for unexpected workflow appearance during tail. Initial scan duplicates work without benefit at P3 scope. |
| D2 | `WorkflowAttachment` no SnapshotWatcher integration | Pushed to P4 to keep P3 surface bounded. Status events (T8) and ENOENT-driven stop (T20) all land in P4. |
| D3 | Sequential step ordering in `start()`: journal → initial agents → dir watch | Matches SPEC §10.2 step 1-3. Journal flush completes before agent transcripts begin so user sees logical start-of-workflow ordering. |
| D4 | Reuse `ClaudeAgent({ verbose }).parser` for each agent transcript | Avoids constructor seams; matches existing patterns in `subagent-detector.ts`. Each agent has its own parser instance (stateful multi-emit). |
| D5 | `attachAgent` is sync-guarded by `knownAgentIds` set check | SPEC §9.3 / S7 — same race-safety pattern as Codex. Initial scan and dir watch race-safe. |
| D6 | `--no-workflow-agents` evaluated as `withWorkflowAgents !== false` in dispatcher | Optional in P1 type. P3 normalizes to bool. |
| D7 | `--workflow-pane` flag is parsed and validated in CLI but NOT executed in P3 | Pane impl is P7. P3 only adds the option to parser to lock the flag set. |
| D8 | No `prefillKnown` call in P3 dispatcher | Direct attach via `--workflow <runId>` skips the detector entirely — detector is started ONLY when running normal mode (P5 path A). P3 dispatcher path does not start detector. |
| D9 | Subagent dir watch uses non-recursive `fs.watch` on `transcriptDir` | Matches Claude `SubagentDetector` pattern. New `agent-{17hex}.jsonl` files trigger attach. |

## Tests (TDD blueprint)

### `tests/claude-workflow/workflow-detector.test.ts` (NEW)

