#### 4.1 Session resolution

Two entry points reach workflow mode:
1. **Explicit flag** `--workflow [runId]` (or `--workflow` for latest in cwd).
2. **Positional path** `agent-tail claude wf_abc12345-def` — `ClaudeSessionFinder.findBySessionId` (P2) already dispatches `wf_*` IDs to `WorkflowSessionFinder`, returning a `SessionFile` with `customTitle.startsWith('wf:')`. The dispatcher trigger must check both.

```typescript
// In main() after agent + session resolution:
const isWorkflowMode =
  options.agentType === 'claude' &&
  (options.workflow !== undefined ||
    sessionFile?.customTitle?.startsWith('wf:') === true);

if (isWorkflowMode) {
  let snapshotPath: string;
  let runId: string;

  if (options.workflow !== undefined) {
    // Explicit-flag path
    const wfFinder = new WorkflowSessionFinder();
    let result: SessionFile | null;
    if (typeof options.workflow === 'string') {
      result = await wfFinder.findBySessionId(options.workflow, {
        project: options.project,
      });
      if (!result) {
        console.error(`Error: workflow run not found: ${options.workflow}`);
        process.exit(1);
      }
    } else {
      // --workflow (no runId) — scope to current cwd
      const filter = cwdToClaudeProjectFilter(process.cwd());
      result = await wfFinder.findLatest({ project: filter });
      if (!result) {
        console.error(
          'Error: no workflow runs found in current cwd. Use --list or --workflow <runId>.'
        );
        process.exit(1);
      }
    }
    snapshotPath = result.path;
  } else {
    // Positional-arg path — sessionFile resolved by ClaudeSessionFinder
    // already dispatches `wf_*` to WorkflowSessionFinder. Use it directly.
    snapshotPath = sessionFile.path;
  }

  // Derive runId from snapshotPath filename basename.
  const m = basename(snapshotPath, '.json').match(
    /^(wf_[0-9a-f]{8}-[0-9a-f]{3})$/
  );
  if (!m) {
    console.error(`Error: failed to derive runId from ${snapshotPath}`);
    process.exit(1);
  }
  runId = m[1]!;

  await startClaudeWorkflowMultiWatch(snapshotPath, runId, formatter, options);
  return;
}
```

